SPARQL Examples (7):
  "List recent observations" -> http://localhost:8080/sparql
    Returns all sosa:Observation instances with result value and timestamp, ordered newest first.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT ?obs ?result ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:hasSimpleResult ?result ;
             sosa:resultTime ?time .
      }
    }
    ORDER BY DESC(?time)
    LIMIT 10
  "Observations by sensor" -> http://localhost:8080/sparql
    Returns observations made by a specific sensor. Bind ?sensor to a sosa:Sensor IRI.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT ?obs ?result ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:madeBySensor ?sensor ;
             sosa:hasSimpleResult ?result ;
             sosa:resultTime ?time .
      }
    }
    ORDER BY DESC(?time)
  "Discover sensors" -> http://localhost:8080/sparql
    Returns all distinct sensors that have recorded observations at this node.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT DISTINCT ?sensor WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:madeBySensor ?sensor .
      }
    }
  "Entity lookup by IRI" -> http://localhost:8080/sparql
    Returns all properties and values for an entity. Replace {entity_iri} with the full entity IRI from the node entity namespace.
    SELECT ?p ?o WHERE {
      GRAPH ?g {
        <{entity_iri}> ?p ?o .
      }
    }
  "Observations with SIO measurements" -> http://localhost:8080/sparql
    Returns observations where the result is encoded via the SIO measurement chain: sio:has-attribute -> sio:MeasuredValue -> sio:has-value. Use this when sosa:hasSimpleResult returns empty.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    PREFIX sio:  <http://semanticscience.org/resource/>
    SELECT ?obs ?value ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:resultTime ?time ;
             sio:has-attribute ?mv .
        ?mv a sio:MeasuredValue ;
            sio:has-value ?value .
      }
    }
    ORDER BY DESC(?time)
    LIMIT 10
  "SIO measurements with units" -> http://localhost:8080/sparql
    Returns SIO measurement chains including the unit label. Traverses: Observation -> sio:has-attribute -> MeasuredValue -> sio:has-unit -> rdfs:label.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    PREFIX sio:  <http://semanticscience.org/resource/>
    PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
    SELECT ?obs ?value ?unit ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:resultTime ?time ;
             sio:has-attribute ?mv .
        ?mv a sio:MeasuredValue ;
            sio:has-value ?value .
        OPTIONAL { ?mv sio:has-unit ?u . ?u rdfs:label ?unit . }
      }
    }
    ORDER BY DESC(?time)
    LIMIT 10
  "Count observations" -> http://localhost:8080/sparql
    Returns the total number of observations stored at this node.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT (COUNT(?obs) AS ?total) WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation .
      }
    }

