  QLever Wikidata SPARQL Endpoint
    URL: https://qlever.cs.uni-freiburg.de/api/wikidata
    Description: Wikidata via QLever — universities, research institutions, cities, organizations. Use for institutional context and geographic enrichment (D20 SDL use case).
    Vocabularies: http://www.wikidata.org/ontology#, http://schema.org/, http://www.wikidata.org/prop/direct/
    Example: "Lookup entity by Wikidata QID"
      PREFIX wdt: <http://www.wikidata.org/prop/direct/>
      PREFIX wd:  <http://www.wikidata.org/entity/>
      PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
      PREFIX schema: <http://schema.org/>
      SELECT ?label ?description ?instanceOf WHERE {
        wd:Q178848 rdfs:label ?label ;
                   schema:description ?description ;
                   wdt:P31 ?instanceOf .
        FILTER(LANG(?label) = "en")
        FILTER(LANG(?description) = "en")
      } LIMIT 5
    Example: "Lookup university location by name"
      PREFIX wdt: <http://www.wikidata.org/prop/direct/>
      PREFIX wd:  <http://www.wikidata.org/entity/>
      PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
      PREFIX schema: <http://schema.org/>
      SELECT ?item ?label ?description ?cityLabel WHERE {
        ?item rdfs:label ?label ;
              schema:description ?description ;
              wdt:P31 wd:Q3918 ;
              wdt:P131 ?city .
        ?city rdfs:label ?cityLabel .
        FILTER(LANG(?label) = "en")
        FILTER(LANG(?description) = "en")
        FILTER(LANG(?cityLabel) = "en")
        FILTER(CONTAINS(LCASE(?label), "notre dame"))
      } LIMIT 5

